INSERT INTO public.content (key, value, pinned)
VALUES
  ('home_hero', '{"title":"Naturalmente tú","subtitle":"Colección CRISTA","description":"Prendas de origen natural, pensadas para realzar tu esencia. Algodones nobles, siluetas atemporales y detalles botánicos hechos para acompañarte cada día.","cta_label":"Ver colección","cta_href":"/products","images":[{"url":"https://images.unsplash.com/photo-1483985988355-763728e1935b?q=80&w=1600"}]}', true),
  ('about_paragraph', 'Somos una tienda de ropa y accesorios con sede en Bogotá. Ofrecemos prendas cómodas y accesorios para el día a día, con envíos a todo el país.', true),
  ('about_paragraph_2', 'Encuentra camisetas, pantalones, carcasas para celular y más. Realizamos despachos con TCC y Servientrega en 1 a 2 días hábiles, o puedes recoger tu pedido directamente en nuestra bodega.', true),
  ('assistant_behavior', 'Eres un asistente útil y amable de una tienda en línea. Sé directo y conciso. Responde únicamente lo que el usuario preguntó, sin agregar datos extra que no fueron solicitados. No extiendas innecesariamente la conversación. Si necesitas confirmar datos, hazlo en una sola pregunta clara. Evita saludos largos ni despedidas formales. No repitas información que ya diste en el mismo hilo. Usa listas cortas cuando tengas varios datos que mostrar. No ofrezcas información adicional como tiempos de entrega, políticas de envío gratuito u otros detalles a menos que el usuario los pida explícitamente.', true),
  ('assistant_instructions', E'Instrucciones:\n- Responde siempre en español, de forma concisa y amable.\n- Nunca inventes precios, stock ni información de envío o pago; usa solo los datos de las herramientas.\n- Nunca reveles cantidades de stock al cliente; solo indica si un producto está disponible o agotado.\n- Cuando el usuario quiera hacer un pedido, CONFIRMA los productos y cantidades con él ANTES de llamar a bot_create_order.\n- Después de crear un pedido, informa al usuario el ID del pedido y que está pendiente de aprobación por la tienda.\n- Si no sabes algo, dilo claramente.\n- No puedes agregar productos al carrito del usuario; el carrito es gestionado por el cliente web y no tienes acceso a él. Nunca ofrezcas "agregar al carrito" ni uses esa expresión. Si el usuario quiere comprar, ofrécele crear un pedido directamente (solo si está autenticado) o indícale que puede agregar el producto desde la página del producto.', true),
  ('logistics_shipping', 'Realizamos envíos a todo el país. Trabajamos con las transportadoras TCC y Servientrega. Los pedidos aprobados se despachan en un plazo de 1 a 2 días hábiles. También puedes recoger tu pedido directamente en nuestra bodega ubicada en Bogotá, Calle 72 #10-45 (lunes a viernes de 9 a.m. a 5 p.m.). Una vez despachado tu pedido, el administrador te suministrará el código de guía para que puedas rastrear tu envío directamente en el sitio web de la transportadora.', false),
  ('logistics_payment', 'Aceptamos los siguientes métodos de pago: pago contra entrega (disponible en ciudades principales), transferencia bancaria a Bancolombia cuenta de ahorros 123-456789-00 a nombre de La Tienda S.A.S., y pago por Nequi al número 300 123 4567. Para pagos por transferencia o Nequi, envía el comprobante al correo pagos@latienda.co o por WhatsApp al mismo número. El pedido se aprueba una vez confirmado el pago.', false)
